// HTML nümunəsi:
/*
<div id="outfitElement">Geyimlər yüklənir...</div>
<button id="loadBtn">Yeni geyimləri yüklə</button>
*/

// 1. XMLHttpRequest ilə AJAX
const outfitElement = document.getElementById("outfitElement");
const loadBtn = document.getElementById("loadBtn");

loadBtn.addEventListener("click", () => {
  const xhr = new XMLHttpRequest();
  xhr.open("GET", "https://api.example.com/outfits", true);
  xhr.onreadystatechange = function() {
    if (xhr.readyState === 4 && xhr.status === 200) {
      outfitElement.textContent = xhr.responseText; // Geyim məlumatları
    }
  };
  xhr.send();
});

// 2. fetch ilə AJAX
loadBtn.addEventListener("click", async () => {
  try {
    const response = await fetch("https://api.example.com/outfits");
    const data = await response.json();
    outfitElement.textContent = data.outfits; // Geyim məlumatları
  } catch (error) {
    outfitElement.textContent = "Xəta: Geyimlər yüklənmədi!";
  }
});

// 3. Dinamik sinif əlavə etmə
loadBtn.addEventListener("click", async () => {
  outfitElement.classList.add("loading");
  const response = await fetch("https://api.example.com/outfits");
  const data = await response.json();
  outfitElement.textContent = data.outfits;
  outfitElement.classList.remove("loading");
  outfitElement.classList.add("loaded");
});

